@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam roundcorner 12
skinparam class {
  BackgroundColor #F7F7F7
  BorderColor #333333
  ArrowColor #333333
  FontSize 22
  AttributeFontSize 22
  HeaderFontSize 26
}

class "Klasse" as Klasse << (A,#BFE7E7) >> {
  navn: String
  beskrivelse: String
  terning: int
}

class "Trollmann" as Trollmann << (C,#BFE3BF) >> {
  trylleformler: ArrayList<String>
}

class "Barbar" as Barbar << (C,#BFE3BF) >> {
  raseriAnfall: int
}

class "Karakter" as Karakter << (C,#BFE3BF) >> {
  navn: String
  klasse : Klasse
  level: int
}

Trollmann --|> Klasse
Barbar --|> Klasse
Karakter --> Klasse
@enduml
